  ('pukao-39f5e973-moex-00189', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '關於交錯訊號掃描（Interlacing）、漸進式掃描（Progressivescan）中的敘述，下列何者錯誤？', '["使用交錯訊號掃描（Interlacing）的畫面較容易閃爍，且畫質相對不精細", "交錯訊號掃描（Interlacing）有分奇偶兩個圖場", "漸進式掃描（Progressivescan）不分奇偶圖場，只有一個圖場一次掃描完整個影格", "使用漸進式掃描（Progressivescan）會使影格較不穩定且易閃爍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00190', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '若一張灰階圖之像素點分布如左圖，在進行影像處理後，其像素點分布結果為右圖，此灰階圖最可能經過 什麼處理？', '["直方圖匹配（Histogrammatching）", "直方圖閥值平衡（Balancedhistogramthresholding）", "直方圖均化（Histogramequalization）", "仿射轉換（AffineTransformation）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00191', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '下列關於HSV色彩空間的敘述，何者錯誤？', '["HSV分別代表色相、飽和度、明度", "色相表示顏色的基本屬性", "飽和度是指色彩的純度，越高表示顏色越亮", "明度是指色彩的亮度，越低表示亮度越暗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00192', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '一個長1920像素，寬1080像素，使用RGB三原色所繪製的畫面，其每個畫面共傳輸2332800Bytes的數 據，此畫面的色深（colordepth）為多少bits？', '["3", "24", "4", "8"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00193', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '有關電荷耦合器（ChargeCoupledDevice）的敘述，下列何者錯誤？', '["利用光電效應（photo-electroniceffect）把光轉化成強弱不等的電流", "是一個線性（linear）的光度量器", "應用於數位照相機及攝影機", "用以將數位訊號類比化成類比訊號"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00194', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '一個字母表A={a0,a1,a2,a3}，其中a0的出現機率0.5，a1的出現機率0.25，a2的出現機率0.125，a3的出 現機率0.125，若以霍夫曼編碼（HuffmanCoding）得到A字母表的碼簿（codebook），下列何者可為正確 答案？', '["a0=00，a1=01，a2=10，a3=11", "a0=0，a1=10，a2=110，a3=111", "a0=0，a1=01，a2=011，a3=0111", "a0=0，a1=1，a2=00，a3=11"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00195', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '下列何者是多媒體通訊系統中，負責傳輸錯誤保護機制？', '["資料編碼與解碼（Sourcecodinganddecoding）", "調變與解調（ModulationandDemodulation）", "通道編碼與解碼（Channelcodinganddecoding）", "多工與通訊網路（MultiplexerandCommunicationNetwork）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00196', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '根據取樣理論，對音源取樣需使用適當「取樣頻率」方能記錄完整聲波，有一音源頻率為15kHz，能清晰 表示此音訊的最低取樣頻率為何？', '["60Hz", "7.5kHz", "15kHz", "30kHz"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00197', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '傳播延遲（Propagation delay）為二進位輸入訊號改變其值時，從輸入傳遞到輸出轉變的延遲時間。以 64 位元來說，下列那一種加法器，其傳播延遲時間最長？', '["前瞻進位加法器（Carry-LookaheadAdder）", "進位選擇加法器（Carry-SelectAdder）", "進位儲存加法器（Carry-SaveAdder）", "漣波進位加法器（Ripple-CarryAdder）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
  ('pukao-39f5e973-moex-00198', 'pukao-39f5e973', 'pukao-39f5e973-moex-111-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '由於人類對於亮度與彩度的敏感度不同，使用色彩空間 YCbCr 的影像或視訊，其彩度分量可以使用次取樣 （subsampling），在輕微影響影像品質的情況下來降低資料量。原來未做次取樣的影像（YCbCr4：4：4） 在經過YCbCr4：2：0次取樣後，其總像素點數為原始影像的幾倍？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:51+00:00", "source_pdf_sha1": "d0cd7ea1e12f", "answer_pdf_sha1": "690af196782e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "446", "s": "2616", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL)
